import { useCallback, useState } from 'react';
import { useQuery, useMutation } from 'convex/react';
import { api } from '../../../../convex/_generated/api';

export function useLeaderboard(game: string) {
  const [submitted, setSubmitted] = useState(false);

  const minScore = useQuery(
    api.leaderboard.getMinQualifyingScore,
    game ? { game } : 'skip'
  );

  const submitScoreMutation = useMutation(api.leaderboard.submitScore);

  const qualifies = useCallback(
    (score: number) => {
      if (score <= 0) return false;
      if (minScore === undefined) return false;
      return score > minScore;
    },
    [minScore]
  );

  const submitScore = useCallback(
    async (playerName: string, score: number) => {
      if (!game || submitted) return;
      await submitScoreMutation({ game, playerName, score });
      setSubmitted(true);
    },
    [game, submitted, submitScoreMutation]
  );

  const reset = useCallback(() => {
    setSubmitted(false);
  }, []);

  return { qualifies, submitScore, submitted, reset };
}
