/* eslint-disable react-hooks/exhaustive-deps */

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { GameHeader } from '../ui/GameHeader';
import { GameCanvas } from '../ui/GameCanvas';
import { GameOverlay } from '../ui/GameOverlay';
import { GameControls } from '../ui/GameControls';
import { isMobile } from '../../../../utils/functions';
import { breakoutAudio } from './utils/audioManager';
import { hapticManager } from '../utils/hapticManager';
import { BreakoutHUD } from './components/BreakoutHUD';

// Import types
import type {
  PowerUpType,
  PowerUp,
  ActivePowerUp,
  Brick,
  Ball,
  Paddle,
  BreakoutGameProps,
} from './types';

// Import constants
import {
  CANVAS_WIDTH,
  CANVAS_HEIGHT,
  PADDLE_HEIGHT,
  PADDLE_COLOR,
  PADDLE_SPEED,
  BALL_RADIUS,
  BALL_COLOR,
  INITIAL_LEVEL,
  BRICK_TYPES,
  POWER_UP_SIZE,
  POWER_UP_SPEED,
  POWER_UP_DURATION,
  POWER_UP_CONFIG,
  BACKGROUND_IMAGE_SRC,
  BRICK_ROW_COUNT,
  BRICK_COLUMN_COUNT,
} from './constants';

// Import utility functions
import {
  createBricks,
  allBricksBroken,
  calculatePaddleWidth,
  calculateBallSpeed,
} from './utils/brickHelpers';
import {
  drawBall,
  drawPaddle,
  drawBricks,
  drawExtraBalls,
  drawPowerUps,
} from './utils/drawingHelpers';
import { collisionDetection } from './utils/collisionHelpers';

const BreakoutGame: React.FC<BreakoutGameProps> = ({
  lives: initialLives,
  setPointsEarned,
  setGameOver,
  brandColor = 'hsl(142, 71%, 45%)',
  skin = 'default',
  gameTitle = '🎮 ROMPE BLOQUES',
  brandLogo,
  maxPoints,
}) => {
  // --- Mobile Detection ---
  const mobile = isMobile();

  // --- Game State ---
  const [gameStarted, setGameStarted] = useState(false);
  const [gamePaused, setGamePaused] = useState(false);
  const [quitGame, setQuitGame] = useState(false);
  const [wasGamePaused, setWasGamePaused] = useState(false);
  const [ballLaunched, setBallLaunched] = useState(false);
  const [instructionsStep, setInstructionsStep] = useState(0);

  // --- Score and Progress ---
  const [level, setLevel] = useState(INITIAL_LEVEL);
  const [points, setPoints] = useState(0);
  const pointsRef = useRef(0);
  const [brokenBlocks, setBrokenBlocks] = useState(0);
  const brokenBlocksRef = useRef(0);
  const [totalBlocks, setTotalBlocks] = useState(BRICK_ROW_COUNT * BRICK_COLUMN_COUNT);
  const [currentLives, setCurrentLives] = useState(initialLives);

  // Active power-ups for UI display
  const [activePowerUpsState, setActivePowerUpsState] = useState<ActivePowerUp[]>([]);

  // --- Refs ---
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameId = useRef<number | null>(null);
  const leftPressedRef = useRef(false);
  const rightPressedRef = useRef(false);

  // Handle control input from GameControls
  const handleControl = useCallback(
    (direction: 'up' | 'down' | 'left' | 'right' | 'action' | 'action2') => {
      if (!gamePaused) {
        if (direction === 'left') {
          leftPressedRef.current = true;
          // Auto-release after a moment to prevent stuck controls
          setTimeout(() => {
            leftPressedRef.current = false;
          }, 100);
        } else if (direction === 'right') {
          rightPressedRef.current = true;
          // Auto-release after a moment to prevent stuck controls
          setTimeout(() => {
            rightPressedRef.current = false;
          }, 100);
        }
      }
    },
    [gamePaused]
  );
  const touchStartX = useRef<number | null>(null);
  const originalPaddleWidth = useRef<number>(calculatePaddleWidth(INITIAL_LEVEL));
  const backgroundImageRef = useRef<HTMLImageElement | null>(null);

  // Ball ref
  const ballRef = useRef<Ball>({
    x: CANVAS_WIDTH / 2,
    y: CANVAS_HEIGHT - 30,
    dx: 0,
    dy: 0,
    radius: BALL_RADIUS,
    speed: calculateBallSpeed(INITIAL_LEVEL),
    color: BALL_COLOR,
  });

  // Paddle ref
  const paddleRef = useRef<Paddle>({
    x: (CANVAS_WIDTH - calculatePaddleWidth(INITIAL_LEVEL)) / 2,
    y: CANVAS_HEIGHT - PADDLE_HEIGHT - 10,
    width: calculatePaddleWidth(INITIAL_LEVEL),
    height: PADDLE_HEIGHT,
    speed: PADDLE_SPEED,
    color: PADDLE_COLOR,
  });

  // Bricks ref
  const bricksRef = useRef<Brick[][]>(createBricks(INITIAL_LEVEL));

  // Power-ups refs
  const powerUpsRef = useRef<PowerUp[]>([]);
  const extraBallsRef = useRef<Ball[]>([]);
  const activePowerUpsRef = useRef<ActivePowerUp[]>([]);

  // --- Helper Functions ---

  const resetBallAndPaddle = useCallback(() => {
    const paddleWidth = calculatePaddleWidth(level);
    const ballSpeed = calculateBallSpeed(level);

    paddleRef.current = {
      x: (CANVAS_WIDTH - paddleWidth) / 2,
      y: CANVAS_HEIGHT - PADDLE_HEIGHT - 10,
      width: paddleWidth,
      height: PADDLE_HEIGHT,
      speed: PADDLE_SPEED,
      color: PADDLE_COLOR,
    };

    ballRef.current = {
      x: CANVAS_WIDTH / 2,
      y: CANVAS_HEIGHT - 30,
      dx: 0,
      dy: 0,
      radius: BALL_RADIUS,
      speed: ballSpeed,
      color: BALL_COLOR,
    };

    setBallLaunched(false);
  }, [level]);

  const levelUp = useCallback(() => {
    const newLevel = level + 1;
    setLevel(newLevel);
    bricksRef.current = createBricks(newLevel);
    brokenBlocksRef.current = 0;
    setBrokenBlocks(0);
    setTotalBlocks(BRICK_ROW_COUNT * BRICK_COLUMN_COUNT);
    resetBallAndPaddle();
    breakoutAudio.playLevelUp();
    hapticManager.levelUp();
  }, [level, resetBallAndPaddle]);

  const loseLife = useCallback(() => {
    setCurrentLives((prev) => prev - 1);
    resetBallAndPaddle();
    breakoutAudio.playLoseLife();
    hapticManager.miss();
  }, [resetBallAndPaddle]);

  const launchBall = useCallback(() => {
    if (!ballLaunched && gameStarted && !gamePaused) {
      const launchAngle = (Math.random() * Math.PI) / 3 - Math.PI / 6; // -30 to +30 degrees
      ballRef.current.dx = ballRef.current.speed * Math.sin(launchAngle);
      ballRef.current.dy = -ballRef.current.speed * Math.cos(launchAngle);
      setBallLaunched(true);
    }
  }, [ballLaunched, gameStarted, gamePaused]);

  // Power-up handling
  const spawnPowerUp = useCallback((x: number, y: number, type: PowerUpType) => {
    const config = POWER_UP_CONFIG[type];
    powerUpsRef.current.push({
      x: x - POWER_UP_SIZE / 2,
      y: y - POWER_UP_SIZE / 2,
      width: POWER_UP_SIZE,
      height: POWER_UP_SIZE,
      type,
      speed: POWER_UP_SPEED,
      color: config.color,
      active: true,
    });
  }, []);

  const activatePowerUp = useCallback((type: PowerUpType) => {
    const now = Date.now();

    switch (type) {
      case 'paddle-grow': {
        originalPaddleWidth.current = paddleRef.current.width;
        paddleRef.current.width = Math.min(paddleRef.current.width * 1.5, CANVAS_WIDTH * 0.3);
        paddleRef.current.x = Math.max(
          0,
          Math.min(CANVAS_WIDTH - paddleRef.current.width, paddleRef.current.x)
        );
        activePowerUpsRef.current.push({
          type,
          endTime: now + POWER_UP_DURATION,
        });
        break;
      }

      case 'paddle-shrink': {
        originalPaddleWidth.current = paddleRef.current.width;
        paddleRef.current.width = Math.max(
          paddleRef.current.width * 0.7,
          60 // PADDLE_MIN_WIDTH
        );
        paddleRef.current.x = Math.max(
          0,
          Math.min(CANVAS_WIDTH - paddleRef.current.width, paddleRef.current.x)
        );
        activePowerUpsRef.current.push({
          type,
          endTime: now + POWER_UP_DURATION,
        });
        break;
      }

      case 'ball-speed': {
        ballRef.current.speed = ballRef.current.speed * 0.7; // Slow down for easier gameplay
        // Update velocity to match new speed
        const currentSpeed = Math.sqrt(ballRef.current.dx ** 2 + ballRef.current.dy ** 2);
        ballRef.current.dx = (ballRef.current.dx / currentSpeed) * ballRef.current.speed;
        ballRef.current.dy = (ballRef.current.dy / currentSpeed) * ballRef.current.speed;
        activePowerUpsRef.current.push({
          type,
          endTime: now + POWER_UP_DURATION,
        });
        break;
      }

      case 'multi-ball': {
        // Create 2 extra balls
        for (let i = 0; i < 2; i++) {
          const angle = (Math.random() * Math.PI) / 2 - Math.PI / 4; // -45 to +45 degrees
          extraBallsRef.current.push({
            x: ballRef.current.x,
            y: ballRef.current.y,
            dx: ballRef.current.speed * Math.sin(angle),
            dy: -Math.abs(ballRef.current.speed * Math.cos(angle)),
            radius: BALL_RADIUS,
            speed: ballRef.current.speed,
            color: BALL_COLOR,
          });
        }
        break;
      }

      case 'extra-life': {
        setCurrentLives((prev) => prev + 1);
        break;
      }
    }
  }, []);

  const updatePowerUps = useCallback(() => {
    const now = Date.now();

    // Update falling power-ups
    powerUpsRef.current = powerUpsRef.current.filter((powerUp) => {
      if (!powerUp.active) return false;

      powerUp.y += powerUp.speed;

      // Check paddle collision
      if (
        powerUp.y + powerUp.height > paddleRef.current.y &&
        powerUp.x < paddleRef.current.x + paddleRef.current.width &&
        powerUp.x + powerUp.width > paddleRef.current.x
      ) {
        activatePowerUp(powerUp.type);
        breakoutAudio.playPowerUpCollect();
        hapticManager.perfectHit();
        return false; // Remove collected power-up
      }

      // Remove if fell off screen
      return powerUp.y < CANVAS_HEIGHT;
    });

    // Check and remove expired power-ups
    activePowerUpsRef.current = activePowerUpsRef.current.filter((activePowerUp) => {
      if (now > activePowerUp.endTime) {
        // Revert power-up effects
        switch (activePowerUp.type) {
          case 'paddle-grow':
          case 'paddle-shrink': {
            paddleRef.current.width = calculatePaddleWidth(level);
            paddleRef.current.x = Math.max(
              0,
              Math.min(CANVAS_WIDTH - paddleRef.current.width, paddleRef.current.x)
            );
            break;
          }
          case 'ball-speed': {
            ballRef.current.speed = calculateBallSpeed(level);
            // Update velocity to match new speed
            const currentSpeed = Math.sqrt(ballRef.current.dx ** 2 + ballRef.current.dy ** 2);
            ballRef.current.dx = (ballRef.current.dx / currentSpeed) * ballRef.current.speed;
            ballRef.current.dy = (ballRef.current.dy / currentSpeed) * ballRef.current.speed;
            break;
          }
        }
        return false;
      }
      return true;
    });

    // Update state for UI display
    setActivePowerUpsState([...activePowerUpsRef.current]);
  }, [activatePowerUp, level]);

  // --- Effects ---

  // Initialize audio and haptics
  useEffect(() => {
    breakoutAudio.init();
    hapticManager.init();
    return () => {
      breakoutAudio.dispose();
    };
  }, []);

  // Load background image
  useEffect(() => {
    const img = new Image();
    if (skin !== 'default') {
      img.src = `/games/breakout/skins/${skin}/bg.webp`;
    } else {
      img.src = BACKGROUND_IMAGE_SRC;
    }
    img.onload = () => {
      backgroundImageRef.current = img;
    };
  }, []);

  // Handle game over when lives reach 0
  useEffect(() => {
    if (currentLives <= 0 && gameStarted) {
      setGameStarted(false);
      setGameOver(true);
      setPointsEarned(points);
    }
  }, [currentLives, gameStarted, points, setGameOver, setPointsEarned]);

  // Keyboard event listeners
  useEffect(() => {
    const keyDownHandler = (e: KeyboardEvent) => {
      if (e.key === 'Right' || e.key === 'ArrowRight') {
        rightPressedRef.current = true;
      } else if (e.key === 'Left' || e.key === 'ArrowLeft') {
        leftPressedRef.current = true;
      } else if (e.key === ' ' && gameStarted && !ballLaunched) {
        e.preventDefault();
        launchBall();
      } else if (e.key === ' ' && gameStarted && ballLaunched) {
        e.preventDefault();
        setGamePaused((prev) => !prev);
      } else if (e.key === 'p' || e.key === 'P') {
        if (gameStarted && ballLaunched) {
          setGamePaused((prev) => !prev);
        }
      }
    };

    const keyUpHandler = (e: KeyboardEvent) => {
      if (e.key === 'Right' || e.key === 'ArrowRight') {
        rightPressedRef.current = false;
      } else if (e.key === 'Left' || e.key === 'ArrowLeft') {
        leftPressedRef.current = false;
      }
    };

    document.addEventListener('keydown', keyDownHandler);
    document.addEventListener('keyup', keyUpHandler);

    return () => {
      document.removeEventListener('keydown', keyDownHandler);
      document.removeEventListener('keyup', keyUpHandler);
    };
  }, [gameStarted, ballLaunched, launchBall]);

  // Touch event listeners
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || !mobile || !gameStarted) return;

    const touchMoveHandler = (e: TouchEvent) => {
      if (!gameStarted || gamePaused) return;

      if (e.touches.length > 0) {
        e.preventDefault();
        const touch = e.touches[0];
        const rect = canvas.getBoundingClientRect();
        const touchX = touch.clientX - rect.left;
        const nextPaddleX = Math.max(0, Math.min(rect.width - paddleRef.current.width, touchX));
        paddleRef.current.x = nextPaddleX * window.devicePixelRatio;
        if (!ballLaunched) {
          ballRef.current.x = paddleRef.current.x + paddleRef.current.width / 2;
        }
      }
    };

    const touchStartHandler = (e: TouchEvent) => {
      if (gamePaused) return;
      if (!ballLaunched) {
        e.preventDefault();
        launchBall();
      }
      if (e.touches.length > 0) {
        touchStartX.current = e.touches[0].clientX;
      }
    };

    const touchEndHandler = () => {
      touchStartX.current = null;
    };

    canvas.addEventListener('touchmove', touchMoveHandler, { passive: false });
    canvas.addEventListener('touchstart', touchStartHandler, { passive: false });
    canvas.addEventListener('touchend', touchEndHandler);

    return () => {
      canvas.removeEventListener('touchmove', touchMoveHandler);
      canvas.removeEventListener('touchstart', touchStartHandler);
      canvas.removeEventListener('touchend', touchEndHandler);
    };
  }, [mobile, gameStarted, gamePaused, ballLaunched, launchBall]);

  // Game Loop Effect
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || !gameStarted) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let lastTime = performance.now();

    const draw = () => {
      const now = performance.now();
      const deltaTime = (now - lastTime) / 1000;
      lastTime = now;

      if (gamePaused || quitGame) {
        animationFrameId.current = requestAnimationFrame(draw);
        return;
      }
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // Draw background
      if (backgroundImageRef.current) {
        // Draw background image if loaded
        ctx.drawImage(backgroundImageRef.current, 0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
        // Add a semi-transparent overlay for better visibility
        ctx.fillStyle = 'rgba(0, 0, 0, 0.3)';
        ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      } else {
        // Fallback: Draw a dark background if image hasn't loaded
        ctx.fillStyle = '#1a1a1a';
        ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      }

      // Draw elements
      drawBricks(ctx, bricksRef.current);
      drawPaddle(ctx, paddleRef.current);
      drawBall(ctx, ballRef.current);
      drawExtraBalls(ctx, extraBallsRef.current);
      drawPowerUps(ctx, powerUpsRef.current);

      if (ballLaunched) {
        // Move paddle
        if (
          rightPressedRef.current &&
          paddleRef.current.x < CANVAS_WIDTH - paddleRef.current.width
        ) {
          paddleRef.current.x += paddleRef.current.speed * deltaTime * 60;
        } else if (leftPressedRef.current && paddleRef.current.x > 0) {
          paddleRef.current.x -= paddleRef.current.speed * deltaTime * 60;
        }

        // Update power-ups
        updatePowerUps();

        // Collision detection for main ball
        const {
          pointsToAdd,
          lifeLost,
          spawnPowerUp: powerUpToSpawn,
          hitPaddle,
          hitWall,
          hitBrick,
        } = collisionDetection(
          ballRef.current,
          bricksRef.current,
          paddleRef.current,
          CANVAS_HEIGHT,
          CANVAS_WIDTH
        );

        if (powerUpToSpawn) {
          spawnPowerUp(powerUpToSpawn.x, powerUpToSpawn.y, powerUpToSpawn.type);
        }

        // Play collision sounds and haptics
        if (hitPaddle) {
          breakoutAudio.playPaddleHit();
          hapticManager.buttonTap();
        }
        if (hitWall) {
          breakoutAudio.playWallHit();
        }
        if (hitBrick && pointsToAdd === 0) {
          // Brick hit but not broken (partial damage)
          breakoutAudio.playBrickHit();
          hapticManager.buttonTap();
        }
        if (pointsToAdd > 0) {
          // Brick fully broken
          breakoutAudio.playBrickBreak();
          hapticManager.goodHit();
        }

        // Handle extra balls
        extraBallsRef.current = extraBallsRef.current.filter((ball) => {
          const result = collisionDetection(
            ball,
            bricksRef.current,
            paddleRef.current,
            CANVAS_HEIGHT,
            CANVAS_WIDTH
          );

          if (result.pointsToAdd > 0) {
            setPoints((prev) => prev + result.pointsToAdd);
            brokenBlocksRef.current += 1;
            setBrokenBlocks(brokenBlocksRef.current);
          }

          if (result.spawnPowerUp) {
            spawnPowerUp(result.spawnPowerUp.x, result.spawnPowerUp.y, result.spawnPowerUp.type);
          }

          // Move extra ball
          ball.x += ball.dx * deltaTime * 60;
          ball.y += ball.dy * deltaTime * 60;

          // Keep extra ball if not lost
          return !result.lifeLost;
        });

        if (pointsToAdd > 0) {
          pointsRef.current += pointsToAdd;
          setPoints(pointsRef.current);
          brokenBlocksRef.current += 1;
          setBrokenBlocks(brokenBlocksRef.current);

          if (maxPoints && pointsRef.current >= maxPoints) {
            setGameStarted(false);
            setGameOver(true);
            setPointsEarned(Math.min(pointsRef.current, maxPoints));
            return;
          }
        }

        // Only lose life if main ball is lost
        if (lifeLost) {
          // Check if there are extra balls
          if (extraBallsRef.current.length > 0) {
            // Move an extra ball to become the main ball
            const newMainBall = extraBallsRef.current.pop()!;
            ballRef.current.x = newMainBall.x;
            ballRef.current.y = newMainBall.y;
            ballRef.current.dx = newMainBall.dx;
            ballRef.current.dy = newMainBall.dy;
          } else {
            loseLife();
            extraBallsRef.current = [];
            powerUpsRef.current = [];
            activePowerUpsRef.current = [];
            return;
          }
        }

        if (allBricksBroken(bricksRef.current)) {
          levelUp();
          extraBallsRef.current = [];
          powerUpsRef.current = [];
          activePowerUpsRef.current = [];
          return;
        }

        // Move ball
        ballRef.current.x += ballRef.current.dx * deltaTime * 60;
        ballRef.current.y += ballRef.current.dy * deltaTime * 60;
      } else {
        // Keep ball centered on paddle before launch
        ballRef.current.x = paddleRef.current.x + paddleRef.current.width / 2;
        ballRef.current.y = paddleRef.current.y - BALL_RADIUS;

        // Move paddle
        if (
          rightPressedRef.current &&
          paddleRef.current.x < CANVAS_WIDTH - paddleRef.current.width
        ) {
          paddleRef.current.x += paddleRef.current.speed * deltaTime * 60;
        } else if (leftPressedRef.current && paddleRef.current.x > 0) {
          paddleRef.current.x -= paddleRef.current.speed * deltaTime * 60;
        }
      }

      animationFrameId.current = requestAnimationFrame(draw);
    };

    draw();

    return () => {
      if (animationFrameId.current) {
        cancelAnimationFrame(animationFrameId.current);
      }
    };
  }, [
    gameStarted,
    gamePaused,
    quitGame,
    ballLaunched,
    level,
    loseLife,
    levelUp,
    updatePowerUps,
    spawnPowerUp,
  ]);

  // --- Game Start/Control Functions ---

  const startGame = () => {
    setInstructionsStep(0);
    setLevel(INITIAL_LEVEL);
    setPoints(0);
    pointsRef.current = 0;
    setBrokenBlocks(0);
    brokenBlocksRef.current = 0;
    setTotalBlocks(BRICK_ROW_COUNT * BRICK_COLUMN_COUNT);
    setCurrentLives(initialLives);
    bricksRef.current = createBricks(INITIAL_LEVEL);
    resetBallAndPaddle();
    powerUpsRef.current = [];
    extraBallsRef.current = [];
    activePowerUpsRef.current = [];
    setGamePaused(false);
    setQuitGame(false);
    setGameStarted(true);
    setBallLaunched(false);
  };

  const cancelQuit = () => {
    setQuitGame(false);
    setGamePaused(wasGamePaused);
  };

  const handleQuitConfirm = () => {
    setPointsEarned(points);
    setGameOver(true);
    setGameStarted(false);
    setBallLaunched(false);
    if (animationFrameId.current) {
      cancelAnimationFrame(animationFrameId.current);
    }
  };

  // --- Component Render ---

  return (
    <div className="game-column-fill" style={{ backgroundColor: brandColor }}>
      {/* Game Header */}
      <GameHeader
        level={level}
        lives={currentLives}
        onPause={
          gameStarted && ballLaunched && !quitGame ? () => setGamePaused(!gamePaused) : undefined
        }
        isPaused={gamePaused}
        brandColor={brandColor}
        isMobile={mobile}
        onQuit={() => {
          setQuitGame(true);
          setWasGamePaused(gamePaused);
          setGamePaused(true);
        }}
        showQuitButton={gameStarted}
        isQuitting={quitGame}
      />

      {/* In-Game HUD */}
      {gameStarted && (
        <BreakoutHUD
          score={points}
          brokenBlocks={brokenBlocks}
          totalBlocks={totalBlocks}
          activePowerUps={activePowerUpsState}
          brandColor={brandColor}
        />
      )}

      {/* Game Container */}
      <div className="game-center-area-tight">
        <div className="game-breakout-game-area" style={{ backgroundColor: brandColor }}>
          {/* Game Canvas */}
          <GameCanvas
            ref={canvasRef}
            width={CANVAS_WIDTH}
            height={CANVAS_HEIGHT}
            style={{
              maxWidth: '100%',
              maxHeight: '100%',
              cursor: gameStarted && !gamePaused && ballLaunched ? 'none' : 'default',
            }}
          />

          {/* Game Overlays */}
          {!gameStarted && (
            <GameOverlay
              type="custom"
              title={gameTitle}
              brandColor={brandColor}
              onAction={
                instructionsStep === 0
                  ? () => setInstructionsStep(1)
                  : instructionsStep === 1
                    ? () => setInstructionsStep(2)
                    : startGame
              }
              actionText={
                instructionsStep === 0
                  ? 'Siguiente →'
                  : instructionsStep === 1
                    ? 'Power-ups →'
                    : '🎮 JUGAR'
              }
              showPressToStart={false}
              customContent={
                <div className="game-start-content">
                  {brandLogo && (
                    <>
                      <span className="game-brand-label">por:</span>
                      <img src={brandLogo} alt="Brand Logo" className="game-brand-logo" />
                    </>
                  )}
                  {instructionsStep === 0 ? (
                    <>
                      {/* Visual elements */}
                      <div
                        style={{
                          display: 'flex',
                          justifyContent: 'center',
                          alignItems: 'center',
                          gap: '0.75rem',
                          fontSize: '0.75rem',
                          color: '#d1d5db',
                        }}
                      >
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.25rem' }}>
                          <div
                            style={{
                              width: '1.5rem',
                              height: '0.5rem',
                              backgroundColor: '#d1d5db',
                              borderRadius: '0.125rem',
                            }}
                          ></div>
                          <p style={{ fontSize: '0.75rem' }}>Paleta</p>
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.25rem' }}>
                          <div
                            style={{
                              backgroundColor: BALL_COLOR,
                              width: '0.5rem',
                              height: '0.5rem',
                              borderRadius: '9999px',
                            }}
                          ></div>
                          <p style={{ fontSize: '0.75rem' }}>Pelota</p>
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.25rem' }}>
                          {BRICK_TYPES.slice(0, 2).map((type) => (
                            <div
                              key={type.color}
                              style={{
                                backgroundColor: type.color,
                                width: '1rem',
                                height: '0.5rem',
                                borderRadius: '0.125rem',
                              }}
                            ></div>
                          ))}
                          <p style={{ fontSize: '0.75rem' }}>Bloques</p>
                        </div>
                      </div>
                      {/* Controls */}
                      <div style={{ textAlign: 'center', fontSize: '0.875rem', color: '#d1d5db' }}>
                        {mobile ? (
                          <>
                            <p>👆 Desliza para mover</p>
                            <p>👆 Toca para lanzar</p>
                          </>
                        ) : (
                          <>
                            <p>⬅️➡️ Flechas para mover</p>
                            <p>⏸ ESPACIO para lanzar/pausar</p>
                          </>
                        )}
                      </div>
                      {/* Skip button */}
                      <button onClick={startGame} className="game-skip-link">
                        Omitir
                      </button>
                    </>
                  ) : instructionsStep === 1 ? (
                    <>
                      <div className="game-start-instructions">
                        <p>🎯 Destruye bloques para ganar puntos</p>
                        <p>🏆 Completa niveles limpiando todos</p>
                        <p>❤️ No dejes caer la pelota</p>
                        <p>📏 La paleta se achica cada nivel</p>
                      </div>
                      {/* Back button */}
                      <button onClick={() => setInstructionsStep(0)} className="game-skip-link">
                        ← Atrás
                      </button>
                    </>
                  ) : (
                    <>
                      <div className="game-start-instructions" style={{ fontSize: '0.75rem' }}>
                        <p
                          style={{
                            fontWeight: 'bold',
                            fontSize: '0.875rem',
                            marginBottom: '0.5rem',
                          }}
                        >
                          ✨ Power-ups disponibles:
                        </p>
                        <p>
                          🔵 <span style={{ color: '#4ade80' }}>Paleta Grande</span> - Aumenta
                          tamaño
                        </p>
                        <p>
                          ⚡ <span style={{ color: '#60a5fa' }}>Bola Lenta</span> - Facilita el
                          juego
                        </p>
                        <p>
                          ⭐ <span style={{ color: '#facc15' }}>Multi-Bola</span> - 3 bolas a la vez
                        </p>
                        <p>
                          ❤️ <span style={{ color: '#f87171' }}>Vida Extra</span> - +1 vida
                        </p>
                        <p style={{ fontSize: '0.75rem', marginTop: '0.5rem', color: '#6b7280' }}>
                          Nivel 4+: 🔴 Paleta pequeña (cuidado!)
                        </p>
                        <p style={{ fontSize: '0.75rem', fontStyle: 'italic' }}>
                          Los bloques con ✨ contienen power-ups
                        </p>
                      </div>
                      {/* Back button */}
                      <button onClick={() => setInstructionsStep(1)} className="game-skip-link">
                        ← Atrás
                      </button>
                    </>
                  )}
                </div>
              }
            />
          )}

          {/* Pause Overlay */}
          {gamePaused && !quitGame && (
            <GameOverlay
              type="pause"
              message="Juego pausado. ¿Listo para seguir?"
              brandColor={brandColor}
              onAction={() => setGamePaused(false)}
              actionText="▶️ CONTINUAR"
            />
          )}

          {/* Quit Confirmation Overlay */}
          {quitGame && (
            <GameOverlay
              type="custom"
              title="¿Salir del Juego?"
              message={`¿Seguro? Registrarás tus puntos actuales (${points}) y perderás las vidas restantes.`}
              brandColor={brandColor}
              customContent={
                <div className="game-quit-buttons">
                  <button onClick={cancelQuit} className="game-quit-btn game-quit-btn-cancel">
                    🔄 Cancelar
                  </button>
                  <button
                    onClick={handleQuitConfirm}
                    className="game-quit-btn game-quit-btn-confirm"
                  >
                    ❌ Salir Ahora
                  </button>
                </div>
              }
            />
          )}
        </div>
      </div>

      {/* Mobile Controls */}
      {mobile && gameStarted && (
        <GameControls onControl={handleControl} layout="horizontal" brandColor={brandColor} />
      )}
    </div>
  );
};

export default BreakoutGame;
