// Fruit bonus item for Pac-Man

import {
	FRUIT_CONFIG,
	FRUIT_ORDER,
	FRUIT_POSITION,
	FRUIT_DURATION_FRAMES,
	FRUIT_SCORE_DURATION_FRAMES,
	FRUIT_DOT_LIMIT_1,
	FRUIT_DOT_LIMIT_2,
	MID_TILE,
} from '../constants'
import type { Position } from '../types'

export class Fruit {
	pixel: Position = { ...FRUIT_POSITION }
	framesLeft: number = 0
	scoreFramesLeft: number = 0
	currentFruitIndex: number = 0

	onNewLevel(level: number): void {
		const clamped = Math.min(level, 13)
		this.currentFruitIndex = FRUIT_ORDER[clamped - 1]
	}

	onDotEat(dotsEaten: number): void {
		if (
			!this.isPresent() &&
			(dotsEaten === FRUIT_DOT_LIMIT_1 || dotsEaten === FRUIT_DOT_LIMIT_2)
		) {
			this.framesLeft = FRUIT_DURATION_FRAMES
		}
	}

	update(): void {
		if (this.framesLeft > 0) {
			this.framesLeft--
		}
		if (this.scoreFramesLeft > 0) {
			this.scoreFramesLeft--
		}
	}

	/**
	 * Test collision with player. Returns points if collected, 0 otherwise.
	 */
	testCollide(playerPixel: Position): number {
		if (
			this.isPresent() &&
			Math.abs(playerPixel.x - this.pixel.x) <= MID_TILE.x &&
			Math.abs(playerPixel.y - this.pixel.y) <= MID_TILE.y
		) {
			const points = this.getPoints()
			this.framesLeft = 0
			this.scoreFramesLeft = FRUIT_SCORE_DURATION_FRAMES
			return points
		}
		return 0
	}

	reset(): void {
		this.framesLeft = 0
		this.scoreFramesLeft = 0
	}

	isPresent(): boolean {
		return this.framesLeft > 0
	}

	isShowingScore(): boolean {
		return this.scoreFramesLeft > 0
	}

	getCurrentFruit(): { name: string; points: number } {
		return FRUIT_CONFIG[this.currentFruitIndex]
	}

	getPoints(): number {
		return this.getCurrentFruit().points
	}
}
