// Direction utilities for Pac-Man

import { Direction, OpenTiles, Position, TilePosition } from '../types'

/**
 * Get clockwise angle from top for a direction
 */
export function getClockwiseAngleFromTop(dirEnum: Direction): number {
	return -dirEnum * (Math.PI / 2)
}

/**
 * Rotate direction counter-clockwise (left)
 */
export function rotateLeft(dirEnum: Direction): Direction {
	return ((dirEnum + 1) % 4) as Direction
}

/**
 * Rotate direction clockwise (right)
 */
export function rotateRight(dirEnum: Direction): Direction {
	return ((dirEnum + 3) % 4) as Direction
}

/**
 * Rotate direction 180 degrees (about face)
 */
export function rotateAboutFace(dirEnum: Direction): Direction {
	return ((dirEnum + 2) % 4) as Direction
}

/**
 * Get direction enum from a direction vector
 */
export function getEnumFromDir(dir: Position): Direction {
	if (dir.x === -1) return Direction.LEFT
	if (dir.x === 1) return Direction.RIGHT
	if (dir.y === -1) return Direction.UP
	if (dir.y === 1) return Direction.DOWN
	return Direction.LEFT // Default
}

/**
 * Set direction vector from a direction enum
 */
export function setDirFromEnum(dir: Position, dirEnum: Direction): void {
	if (dirEnum === Direction.UP) {
		dir.x = 0
		dir.y = -1
	} else if (dirEnum === Direction.RIGHT) {
		dir.x = 1
		dir.y = 0
	} else if (dirEnum === Direction.DOWN) {
		dir.x = 0
		dir.y = 1
	} else if (dirEnum === Direction.LEFT) {
		dir.x = -1
		dir.y = 0
	}
}

/**
 * Get a new direction vector from an enum
 */
export function getDirFromEnum(dirEnum: Direction): Position {
	const dir = { x: 0, y: 0 }
	setDirFromEnum(dir, dirEnum)
	return dir
}

/**
 * Return the direction of the open surrounding tile closest to target.
 * Uses euclidean distance for pathfinding.
 */
export function getTurnClosestToTarget(
	tile: TilePosition,
	targetTile: TilePosition,
	openTiles: OpenTiles
): Direction {
	let minDist = Infinity
	let dirEnum: Direction = Direction.UP
	const dir = { x: 0, y: 0 }

	for (let i = 0; i < 4; i++) {
		if (openTiles[i as Direction]) {
			setDirFromEnum(dir, i as Direction)
			const dx = dir.x + tile.x - targetTile.x
			const dy = dir.y + tile.y - targetTile.y
			const dist = dx * dx + dy * dy
			if (dist < minDist) {
				minDist = dist
				dirEnum = i as Direction
			}
		}
	}
	return dirEnum
}

/**
 * Check if the tile in the given direction is walkable
 */
export function isNextTileFloor(
	tile: TilePosition,
	dir: Position,
	isFloorTile: (x: number, y: number) => boolean
): boolean {
	return isFloorTile(tile.x + dir.x, tile.y + dir.y)
}
