// Ghost targeting algorithms

import { Direction, TilePosition } from '../types'
import { Ghost } from './Ghost'
import type { Player } from './Player'

/**
 * Blinky (Red Ghost) - Directly targets Pac-Man
 */
export class Blinky extends Ghost {
	private playerRef: Player | null = null

	constructor() {
		super('#ff0000')
	}

	setPlayerRef(player: Player): void {
		this.playerRef = player
	}

	getTargetTile(): TilePosition {
		if (this.playerRef) {
			return { x: this.playerRef.tile.x, y: this.playerRef.tile.y }
		}
		return { x: 0, y: 0 }
	}
}

/**
 * Pinky (Pink Ghost) - Targets 4 tiles ahead of Pac-Man
 * Includes the original arcade bug where UP adds -4 to X
 */
export class Pinky extends Ghost {
	private playerRef: Player | null = null

	constructor() {
		super('#ffb8ff')
	}

	setPlayerRef(player: Player): void {
		this.playerRef = player
	}

	getTargetTile(): TilePosition {
		if (!this.playerRef) return { x: 0, y: 0 }

		let px = this.playerRef.tile.x + 4 * this.playerRef.dir.x
		let py = this.playerRef.tile.y + 4 * this.playerRef.dir.y

		// Original arcade bug: when facing UP, also subtract 4 from X
		if (this.playerRef.dirEnum === Direction.UP) {
			px -= 4
		}

		return { x: px, y: py }
	}
}

/**
 * Inky (Cyan Ghost) - Targets relative to Blinky
 * Takes point 2 tiles ahead of Pac-Man and doubles vector from Blinky
 * Includes the original arcade bug where UP adds -2 to X
 */
export class Inky extends Ghost {
	private playerRef: Player | null = null
	private blinkyRef: Blinky | null = null

	constructor() {
		super('#00ffff')
	}

	setPlayerRef(player: Player): void {
		this.playerRef = player
	}

	setBlinkyRef(blinky: Blinky): void {
		this.blinkyRef = blinky
	}

	getTargetTile(): TilePosition {
		if (!this.playerRef || !this.blinkyRef) return { x: 0, y: 0 }

		let px = this.playerRef.tile.x + 2 * this.playerRef.dir.x
		let py = this.playerRef.tile.y + 2 * this.playerRef.dir.y

		// Original arcade bug: when facing UP, also subtract 2 from X
		if (this.playerRef.dirEnum === Direction.UP) {
			px -= 2
		}

		// Double the vector from Blinky to the offset point
		return {
			x: this.blinkyRef.tile.x + 2 * (px - this.blinkyRef.tile.x),
			y: this.blinkyRef.tile.y + 2 * (py - this.blinkyRef.tile.y),
		}
	}
}

/**
 * Clyde (Orange Ghost) - Targets Pac-Man when far, corner when close
 * If distance to Pac-Man >= 8 tiles: target Pac-Man
 * If distance < 8 tiles: target corner (flee behavior)
 */
export class Clyde extends Ghost {
	private playerRef: Player | null = null

	constructor() {
		super('#ffb851')
	}

	setPlayerRef(player: Player): void {
		this.playerRef = player
	}

	getTargetTile(): TilePosition {
		if (!this.playerRef) return this.cornerTile

		// Calculate distance to Pac-Man (using next tile position)
		const dx = this.playerRef.tile.x - (this.tile.x + this.dir.x)
		const dy = this.playerRef.tile.y - (this.tile.y + this.dir.y)
		const distSquared = dx * dx + dy * dy

		// 8 tiles squared = 64
		if (distSquared >= 64) {
			this.targetting = 'pacman'
			return { x: this.playerRef.tile.x, y: this.playerRef.tile.y }
		} else {
			this.targetting = 'corner'
			return { x: this.cornerTile.x, y: this.cornerTile.y }
		}
	}
}

/**
 * Create all four ghosts with proper starting configurations
 */
export function createGhosts(): {
	blinky: Blinky
	pinky: Pinky
	inky: Inky
	clyde: Clyde
} {
	const blinky = new Blinky()
	const pinky = new Pinky()
	const inky = new Inky()
	const clyde = new Clyde()

	// Set Inky's reference to Blinky for targeting
	inky.setBlinkyRef(blinky)

	return { blinky, pinky, inky, clyde }
}
