import React, { useCallback, useEffect, useRef, useState } from 'react'
import { isMobile } from '../../../../utils/functions'
import { type Player } from './hooks/usePlayer'
import { useInterval } from './hooks/useInterval'
import { usePlayer } from './hooks/usePlayer'
import { useBoard } from './hooks/useBoard'
import { GameHeader } from '../ui/GameHeader'
import { GameOverlay } from '../ui/GameOverlay'
import { GameControls } from '../ui/GameControls'
import { tetrisAudio } from './utils/audioManager'
import { hapticManager } from '../utils/hapticManager'

export const BOARD_WIDTH = 10
export const BOARD_HEIGHT = 20

const TETROMINOS = {
	0: { shape: [[0]], color: '#000000' },
	I: {
		shape: [
			[0, 'I', 0, 0],
			[0, 'I', 0, 0],
			[0, 'I', 0, 0],
			[0, 'I', 0, 0],
		],
		color: '#50e3e4', // RGB(80,227,230)
	},
	J: {
		shape: [
			[0, 'J', 0],
			[0, 'J', 0],
			['J', 'J', 0],
		],
		color: '#245fdf', // RGB(36,95,223)
	},
	L: {
		shape: [
			[0, 'L', 0],
			[0, 'L', 0],
			[0, 'L', 'L'],
		],
		color: '#dfad24', // RGB(223,173,36)
	},
	O: {
		shape: [
			['O', 'O'],
			['O', 'O'],
		],
		color: '#dfd924', // RGB(223,217,36)
	},
	S: {
		shape: [
			[0, 'S', 'S'],
			['S', 'S', 0],
			[0, 0, 0],
		],
		color: '#30d934', // RGB(48,211,56)
	},
	T: {
		shape: [
			[0, 0, 0],
			['T', 'T', 'T'],
			[0, 'T', 0],
		],
		color: '#843dc6', // RGB(132,61,198)
	},
	Z: {
		shape: [
			['Z', 'Z', 0],
			[0, 'Z', 'Z'],
			[0, 0, 0],
		],
		color: '#e34e4e', // RGB(227,78,78)
	},
}

export type BoardCell = [keyof typeof TETROMINOS, string]
export type BoardType = BoardCell[][]

export const createBoard = () => {
	return Array.from(Array(BOARD_HEIGHT), () =>
		Array(BOARD_WIDTH).fill([0, 'clear'])
	)
}

export const randomTetromino = () => {
	const tetrominos = [
		'I',
		'J',
		'L',
		'O',
		'S',
		'T',
		'Z',
	] as (keyof typeof TETROMINOS)[]
	const randTetromino =
		tetrominos[Math.floor(Math.random() * tetrominos.length)]
	return TETROMINOS[randTetromino]
}

export const isColliding = (
	player: Player,
	board: BoardType,
	{ x: moveX, y: moveY }: { x: number; y: number }
) => {
	// Using for loops to be able to return (and break). Not possible with forEach
	for (let y = 0; y < player.tetromino.length; y += 1) {
		for (let x = 0; x < player.tetromino[y].length; x += 1) {
			// 1. Check that we're on an actual Tetromino cell
			if (player.tetromino[y][x] !== 0) {
				if (
					// 2. Check that our move is inside the game areas height (y)
					// That we're not moving through the bottom of the grid
					!board[y + player.pos.y + moveY] ||
					// 3. Check that our move is inside the game areas width (x)
					!board[y + player.pos.y + moveY][x + player.pos.x + moveX] ||
					// 4. Check that the cell we're moving to isn't set to clear
					board[y + player.pos.y + moveY][x + player.pos.x + moveX][1] !==
						'clear'
				) {
					return true
				}
			}
		}
	}
}

type CellProps = {
	type: keyof typeof TETROMINOS
	isClearing?: boolean
}

const Cell: React.FC<CellProps> = ({ type, isClearing }) => {
	const color = TETROMINOS[type].color
	const isEmpty = type === 0

	return (
		<div
			className={`game-cell${!isEmpty ? ' game-cell-filled' : ''}${isClearing ? ' game-animate-flash' : ''}`}
			style={{
				backgroundColor: isEmpty
					? 'transparent'
					: isClearing
						? '#ffffff'
						: color,
				borderColor: isEmpty
					? 'rgba(255, 255, 255, 0.1)'
					: isClearing
						? '#ffffff'
						: `${color}88`,
				borderWidth: isEmpty ? '1px' : '2px',
				boxShadow: isEmpty
					? 'none'
					: `inset 0 1px 2px rgba(255,255,255,0.3), inset 0 -1px 2px rgba(0,0,0,0.3)`,
				transform: isClearing ? 'scale(1.1)' : 'scale(1)',
				transition: isClearing ? 'all 0.3s' : 'none',
			}}
		/>
	)
}

type BoardProps = {
	board: BoardType
	clearingRows?: number[]
}

const Board: React.FC<BoardProps> = ({ board, clearingRows = [] }) => {
	return (
		<div className="game-board-tetris">
			{board.map((row, y) =>
				row.map((cell, x) => (
					<Cell
						key={`${y}-${x}`}
						type={cell[0]}
						isClearing={clearingRows.includes(y)}
					/>
				))
			)}
		</div>
	)
}

type NextPieceProps = {
	shape: (string | number)[][]
	color: string
}

const NextPiece: React.FC<NextPieceProps> = ({ shape, color }) => {
	return (
		<div
			className="game-tetris-next-grid"
			style={{
				gridTemplateColumns: `repeat(${shape[0]?.length || 0}, 1fr)`,
				gridTemplateRows: `repeat(${shape.length}, 1fr)`,
			}}
		>
			{shape.map((row, y) =>
				row.map((cell, x) => (
					<div
						key={`${y}-${x}`}
						className="game-cell"
						style={{
							backgroundColor: cell !== 0 ? color : 'transparent',
							borderColor:
								cell !== 0 ? `${color}88` : 'rgba(255, 255, 255, 0.1)',
							borderWidth: cell !== 0 ? '2px' : '1px',
							boxShadow:
								cell !== 0
									? `inset 0 1px 2px rgba(255,255,255,0.3), inset 0 -1px 2px rgba(0,0,0,0.3)`
									: 'none',
						}}
					/>
				))
			)}
		</div>
	)
}

interface TetrisGameProps {
	lives: number
	setPointsEarned: (points: number) => void
	setGameOver: (isOver: boolean) => void
	brandColor?: string
	skin?: string
	gameTitle?: string
	brandLogo?: string
	maxPoints?: number
}

const TetrisGame: React.FC<TetrisGameProps> = ({
	lives,
	setPointsEarned,
	setGameOver,
	brandColor,
	skin = 'default',
	gameTitle = 'TETRIS',
	brandLogo,
	maxPoints,
}) => {
	const mobile = isMobile()

	const [gameStarted, setGameStarted] = useState(false)
	const [gamePaused, setGamePaused] = useState(false)
	const [gameOver, setGameOverState] = useState(false)
	const [quitGame, setQuitGame] = useState(false)
	const [wasGamePaused, setWasGamePaused] = useState(false)

	const [currentLives, setCurrentLives] = useState(lives)
	const [points, setPoints] = useState(0)
	const pointsRef = useRef(0)
	const [level, setLevel] = useState(1)
	// eslint-disable-next-line @typescript-eslint/no-unused-vars
	const [_totalLinesCleared, setTotalLinesCleared] = useState(0)
	const [nextPiece, setNextPiece] = useState(randomTetromino())

	const [showLevelUp, setShowLevelUp] = useState(false)

	const [dropTime, setDropTime] = useState<null | number>(null)
	const [intervalSpeed, setIntervalSpeed] = useState<number>(1000)

	const { player, updatePlayerPos, resetPlayer, playerRotate } = usePlayer()
	const { board, setBoard, rowsCleared, clearingRows } = useBoard(
		player,
		() => {
			resetPlayerWithNextPiece()
		}
	)

	const touchTimeoutRef = useRef<any>(null)

	const resetPlayerWithNextPiece = useCallback(() => {
		if (nextPiece) {
			resetPlayer(nextPiece.shape)
			setNextPiece(randomTetromino())
		}
	}, [nextPiece, resetPlayer])

	const movePlayer = useCallback(
		(dir: number) => {
			if (!isColliding(player, board, { x: dir, y: 0 })) {
				updatePlayerPos({ x: dir, y: 0, collided: false })
				tetrisAudio.playMove()
			}
		},
		[player, board, updatePlayerPos]
	)

	const handleControl = useCallback(
		(direction: 'up' | 'down' | 'left' | 'right' | 'action' | 'action2') => {
			if (gameOver || gamePaused) return

			switch (direction) {
				case 'up':
					playerRotate(board)
					tetrisAudio.playRotate()
					hapticManager.buttonTap()
					break
				case 'down':
					// Start fast drop
					setDropTime(30)
					break
				case 'left':
					movePlayer(-1)
					break
				case 'right':
					movePlayer(1)
					break
			}
		},
		[gameOver, gamePaused, board, playerRotate, movePlayer]
	)

	const handleControlEnd = useCallback(
		(direction: 'up' | 'down' | 'left' | 'right' | 'action' | 'action2') => {
			if (direction === 'down') {
				// Reset to normal drop speed
				setDropTime(intervalSpeed)
			}
		},
		[intervalSpeed]
	)

	const keyUp = ({ keyCode }: { keyCode: number }): void => {
		if (!gameOver) {
			if (keyCode === 40) {
				setDropTime(intervalSpeed)
			}
		}
	}

	const move = ({
		keyCode,
		repeat,
	}: {
		keyCode: number
		repeat: boolean
	}): void => {
		if (!gamePaused || gameOver) {
			if (keyCode === 37) {
				movePlayer(-1)
			} else if (keyCode === 39) {
				movePlayer(1)
			} else if (keyCode === 40) {
				// just call once
				if (repeat) return
				setDropTime(30)
			} else if (keyCode === 38) {
				playerRotate(board)
				tetrisAudio.playRotate()
			}
		}
	}

	const drop = () => {
		if (!isColliding(player, board, { x: 0, y: 1 })) {
			updatePlayerPos({ x: 0, y: 1, collided: false })
		} else {
			if (player.pos.y < 1) {
				setCurrentLives(currentLives - 1)
				if (currentLives - 1 <= 0) {
					setGameOverState(true)
					setGameOver(true)
					setPointsEarned(points)
					setDropTime(null)
					tetrisAudio.playGameOver()
					hapticManager.miss()
				} else {
					setBoard(createBoard())
					hapticManager.miss()
				}
			} else {
				updatePlayerPos({ x: 0, y: 0, collided: true })
				tetrisAudio.playLock()
				hapticManager.buttonTap()
			}
		}
	}

	const startGame = () => {
		setGameStarted(true)
		setBoard(createBoard())
		setDropTime(intervalSpeed) // Use initial speed
		setNextPiece(randomTetromino())
		resetPlayerWithNextPiece()
		setGameOverState(false)
		setPoints(0)
		setCurrentLives(lives)
		setLevel(1)
		setTotalLinesCleared(0)
		setQuitGame(false)
	}

	const cancelQuit = () => {
		setQuitGame(false)
		setGamePaused(wasGamePaused)
	}

	const handleQuitConfirm = () => {
		setPointsEarned(points)
		setGameOver(true)
		setGameStarted(false)
		setDropTime(null)
	}

	const preventDefaultForScrollKeys = (e: any) => {
		const keys: any = { 37: 1, 38: 1, 39: 1, 40: 1 }
		if (keys[e.keyCode] === 1) {
			e.preventDefault()
			return false
		}
	}

	useEffect(() => {
		window.addEventListener('keydown', preventDefaultForScrollKeys, false)
		tetrisAudio.init()
		hapticManager.init()
		return () => {
			tetrisAudio.dispose()
		}
	}, [])

	useInterval(() => {
		if (gameStarted && !gameOver && !gamePaused) {
			drop()
		}
	}, dropTime)

	useEffect(() => {
		if (rowsCleared > 0) {
			// Calculate points based on lines cleared
			let pointsEarned = 0
			switch (rowsCleared) {
				case 1:
					pointsEarned = 100 * level
					hapticManager.goodHit()
					break
				case 2:
					pointsEarned = 300 * level
					hapticManager.perfectHit()
					break
				case 3:
					pointsEarned = 500 * level
					hapticManager.perfectHit()
					break
				case 4:
					pointsEarned = 800 * level // Tetris!
					hapticManager.comboMilestone()
					break
				default:
					pointsEarned = 100 * level * rowsCleared
					hapticManager.goodHit()
			}

			// Play line clear sound
			tetrisAudio.playLineClear(rowsCleared)

			const newPoints = pointsRef.current + pointsEarned
			pointsRef.current = newPoints
			setPoints(newPoints)

			if (maxPoints && newPoints >= maxPoints) {
				setGameOverState(true)
				setGameOver(true)
				setPointsEarned(Math.min(newPoints, maxPoints))
				setDropTime(null)
				return
			}

			setTotalLinesCleared(prev => {
				const newTotal = prev + rowsCleared
				// Level up every 10 lines
				const newLevel = Math.floor(newTotal / 10) + 1
				if (newLevel > level) {
					setLevel(newLevel)
					hapticManager.levelUp()
					tetrisAudio.playLevelUp()
					setShowLevelUp(true)
				}
				return newTotal
			})
			setDropTime(intervalSpeed)
		}
	}, [
		rowsCleared,
		level,
		intervalSpeed,
		maxPoints,
		setGameOver,
		setPointsEarned,
	])

	// Adjust the speed of the game according to the level
	useEffect(() => {
		// Speed formula: 1000ms - (level * 50ms), minimum 100ms
		const newSpeed = Math.max(100, 1000 - (level - 1) * 50)
		setIntervalSpeed(newSpeed)
	}, [level])

	useEffect(() => {
		setDropTime(intervalSpeed) // Update dropTime when intervalSpeed changes
	}, [intervalSpeed])

	// Auto-dismiss level-up animation
	useEffect(() => {
		if (showLevelUp) {
			const timer = setTimeout(() => setShowLevelUp(false), 1500)
			return () => clearTimeout(timer)
		}
	}, [showLevelUp])

	// Add the event listeners on mount and remove them on unmount
	useEffect(() => {
		const handleKeyDown = (e: KeyboardEvent) => move(e)
		const handleKeyUp = (e: KeyboardEvent) => keyUp(e)

		window.addEventListener('keydown', handleKeyDown)
		window.addEventListener('keyup', handleKeyUp)

		return () => {
			window.removeEventListener('keydown', handleKeyDown)
			window.removeEventListener('keyup', handleKeyUp)
		}
	// eslint-disable-next-line react-hooks/exhaustive-deps
	}, [
		gamePaused,
		gameOver,
		player,
		board,
		intervalSpeed,
		movePlayer,
		playerRotate,
	])

	// Cleanup timeouts on unmount
	useEffect(() => {
		const ref = touchTimeoutRef.current
		return () => {
			if (ref) {
				clearTimeout(ref)
			}
		}
	}, [])

	return (
		<div
			className="game-column"
			style={{ backgroundColor: brandColor ? brandColor : '#111827' }}
		>
			{/* Game Header */}
			<GameHeader
				level={level}
				lives={currentLives}
				score={points}
				onPause={() => setGamePaused(!gamePaused)}
				isPaused={gamePaused}
				brandColor={brandColor}
				isMobile={mobile}
				onQuit={() => {
					setQuitGame(true)
					setWasGamePaused(gamePaused)
					setGamePaused(true)
				}}
				showQuitButton={gameStarted}
				isQuitting={quitGame}
			/>
			{/* Game Container */}
			<div className="game-center-area-tight">
				<div style={{ position: 'relative', width: '100%', height: '100%' }}>
					{/* Game Board */}
					<div
						className="game-board-content"
						onKeyDown={move}
						onKeyUp={keyUp}
					>
						<div className="game-tetris-layout">
							{/* Main Board */}
							<div className="game-tetris-column">
								<Board board={board} clearingRows={clearingRows} />
							</div>

							{/* Next Piece Preview */}
							<div className="game-tetris-sidebar">
								{/* Score HUD */}
								<div className="game-tetris-score-hud">
									<div className="game-tetris-score-value">
										{points.toLocaleString()}
									</div>
									<div className="game-tetris-score-meta">
										<span>Nv. {level}</span>
										<span>❤️ {currentLives}</span>
									</div>
								</div>
								<h3 className="game-tetris-next-label">
									SIGUIENTE
								</h3>
								<div className="game-next-piece-box">
									<NextPiece shape={nextPiece.shape} color={nextPiece.color} />
								</div>
								{skin !== 'default' && (
									<div className="game-tetris-ad">
										<img
											src={`/games/tetris/skins/${skin}/ad.webp`}
											alt={`${skin} skin - Ad 200x600`}
											className="game-tetris-ad-img"
										/>
									</div>
								)}
							</div>
						</div>
					</div>

					{/* Level Up Animation */}
					{showLevelUp && (
						<div className="game-overlay-z20">
							<div
								style={{
									textAlign: 'center',
									animation: 'tetrisLevelUp 1.5s ease-out forwards',
								}}
							>
								<div
									className="game-tetris-level-up-text"
									style={{
										color: '#c084fc',
										textShadow:
											'0 0 20px rgba(192, 132, 252, 0.8), 0 0 40px rgba(192, 132, 252, 0.4), 0 0 60px rgba(168, 85, 247, 0.3)',
									}}
								>
									NIVEL {level}
								</div>
							</div>
							<style>{`
								@keyframes tetrisLevelUp {
									0% { transform: scale(0.5); opacity: 0; }
									20% { transform: scale(1.2); opacity: 1; }
									40% { transform: scale(1); opacity: 1; }
									70% { transform: scale(1); opacity: 1; }
									100% { transform: scale(1.1); opacity: 0; }
								}
							`}</style>
						</div>
					)}

					{/* Game Overlays */}
					{gamePaused && !quitGame && (
						<div className="game-overlay-z10">
							<GameOverlay
								type="pause"
								brandColor={brandColor}
								onAction={() => setGamePaused(false)}
							/>
						</div>
					)}

					{/* Quit Confirmation Overlay */}
					{quitGame && (
						<div className="game-overlay-z10">
							<GameOverlay
								type="custom"
								title="¿Salir del Juego?"
								message={`¿Seguro? Registrarás tus puntos actuales (${points}) y perderás las vidas restantes.`}
								brandColor={brandColor}
								customContent={
									<div className="game-quit-buttons">
										<button
											onClick={cancelQuit}
											className="game-quit-btn game-quit-btn-cancel"
										>
											🔄 Cancelar
										</button>
										<button
											onClick={handleQuitConfirm}
											className="game-quit-btn game-quit-btn-confirm"
										>
											❌ Salir Ahora
										</button>
									</div>
								}
							/>
						</div>
					)}

					{gameOver && (
						<div className="game-overlay-z10">
							<GameOverlay
								type="gameOver"
								score={points}
								brandColor={brandColor}
							/>
						</div>
					)}

					{!gameStarted && (
						<div className="game-overlay-z10 game-overlay-clickable">
							<GameOverlay
								type="custom"
								brandColor={brandColor}
								onAction={startGame}
								actionText="🎮 JUGAR"
								showPressToStart={false}
								customContent={
									<div className="game-start-content-lg">
										<h1 className="game-start-title-lg game-animate-pulse" style={{ color: '#c084fc', marginBottom: '0.5rem' }}>
											{gameTitle}
										</h1>
										{brandLogo && (
											<>
												<span className="game-brand-label">por:</span>
												<img
													src={brandLogo}
													alt="Brand Logo"
													className="game-brand-logo"
												/>
											</>
										)}
										<div className="game-start-instructions">
											<p>🧩 Completa líneas horizontales</p>
											<p>⬆️ Rota las piezas con flecha arriba</p>
											<p>⬇️ Acelera la caída con flecha abajo</p>
										</div>
										<div className="game-start-footer">
											<p>
												Usa las flechas del teclado o los controles táctiles
											</p>
										</div>
									</div>
								}
							/>
						</div>
					)}
				</div>
			</div>
			{/* Mobile Controls */}
			{mobile && gameStarted && (
				<GameControls
					onControl={handleControl}
					onControlEnd={handleControlEnd}
					layout="arrows"
					brandColor={brandColor}
				/>
			)}
		</div>
	)
}

export default TetrisGame
