import * as Tone from 'tone'

export class PacmanAudioManager {
	private initialized = false
	private muted = false

	// Synthesizers
	private eatingSynth: Tone.Synth | null = null
	private powerSynth: Tone.PolySynth | null = null
	private ghostEatSynth: Tone.PolySynth | null = null
	private deathSynth: Tone.Synth | null = null
	private startSynth: Tone.PolySynth | null = null
	private extraLifeSynth: Tone.PolySynth | null = null

	// Eating loop state
	private eatingLoop: Tone.Loop | null = null
	private isEating = false
	private lastEatTime = 0
	private readonly EAT_TIMEOUT = 0.15 // Stop waka after this many seconds of no eating

	// Track start jingle played
	private startJinglePlayed = false

	async init(): Promise<void> {
		if (this.initialized) return

		await Tone.start()

		// Eating synth - "waka" sound
		this.eatingSynth = new Tone.Synth({
			oscillator: { type: 'square' },
			envelope: {
				attack: 0.005,
				decay: 0.04,
				sustain: 0,
				release: 0.02,
			},
			volume: -12,
		}).toDestination()

		// Power pellet synth - eerie ascending siren
		this.powerSynth = new Tone.PolySynth(Tone.Synth, {
			oscillator: { type: 'sine' },
			envelope: {
				attack: 0.01,
				decay: 0.15,
				sustain: 0.2,
				release: 0.3,
			},
			volume: -10,
		}).toDestination()

		// Ghost eaten synth - triumphant chomping
		this.ghostEatSynth = new Tone.PolySynth(Tone.Synth, {
			oscillator: { type: 'square' },
			envelope: {
				attack: 0.01,
				decay: 0.1,
				sustain: 0.1,
				release: 0.15,
			},
			volume: -10,
		}).toDestination()

		// Death synth - descending sad tones
		this.deathSynth = new Tone.Synth({
			oscillator: { type: 'triangle' },
			envelope: {
				attack: 0.01,
				decay: 0.2,
				sustain: 0.1,
				release: 0.3,
			},
			volume: -8,
		}).toDestination()

		// Start jingle synth - intro fanfare
		this.startSynth = new Tone.PolySynth(Tone.Synth, {
			oscillator: { type: 'square' },
			envelope: {
				attack: 0.01,
				decay: 0.15,
				sustain: 0.2,
				release: 0.2,
			},
			volume: -10,
		}).toDestination()

		// Extra life synth - triumphant fanfare
		this.extraLifeSynth = new Tone.PolySynth(Tone.Synth, {
			oscillator: { type: 'sawtooth' },
			envelope: {
				attack: 0.01,
				decay: 0.15,
				sustain: 0.2,
				release: 0.4,
			},
			volume: -8,
		}).toDestination()

		// Create eating loop (alternates between two notes for "waka-waka")
		let wakaToggle = false
		this.eatingLoop = new Tone.Loop(time => {
			if (!this.eatingSynth || this.muted) return
			const note = wakaToggle ? 'G4' : 'C5'
			this.eatingSynth.triggerAttackRelease(note, '32n', time)
			wakaToggle = !wakaToggle
		}, 0.08) // Rapid waka-waka rhythm

		this.initialized = true
	}

	// Play start jingle (classic Pac-Man intro approximation)
	playStartJingle(): void {
		if (!this.initialized || this.muted || !this.startSynth) return
		if (this.startJinglePlayed) return // Only play once per level

		this.startJinglePlayed = true
		const now = Tone.now()

		// Classic Pac-Man intro melody (approximation)
		const intro = [
			{ note: 'C4', time: 0 },
			{ note: 'C5', time: 0.15 },
			{ note: 'G4', time: 0.3 },
			{ note: 'E4', time: 0.45 },
			{ note: 'C5', time: 0.65 },
			{ note: 'G4', time: 0.8 },
			{ note: 'E4', time: 0.95 },
		]

		intro.forEach(({ note, time }) => {
			this.startSynth!.triggerAttackRelease(note, '8n', now + time)
		})
	}

	// Reset start jingle flag (call on new level)
	resetStartJingle(): void {
		this.startJinglePlayed = false
	}

	// Start eating sound (called when pellet eaten)
	startEating(): void {
		if (!this.initialized || this.muted || !this.eatingLoop) return

		this.lastEatTime = Tone.now()

		if (!this.isEating) {
			this.isEating = true
			this.eatingLoop.start()
			Tone.getTransport().start()
		}
	}

	// Stop eating sound
	stopEating(): void {
		if (!this.eatingLoop) return

		if (this.isEating) {
			this.isEating = false
			this.eatingLoop.stop()
		}
	}

	// Check if eating should stop (call every frame)
	updateEating(): void {
		if (!this.isEating) return

		const now = Tone.now()
		if (now - this.lastEatTime > this.EAT_TIMEOUT) {
			this.stopEating()
		}
	}

	// Play power pellet sound (energizer activation)
	playPowerPellet(): void {
		if (!this.initialized || this.muted || !this.powerSynth) return
		const now = Tone.now()

		// Ascending siren-like effect
		const siren = ['C4', 'E4', 'G4', 'C5', 'E5']
		siren.forEach((note, i) => {
			this.powerSynth!.triggerAttackRelease(note, '16n', now + i * 0.06)
		})
	}

	// Play ghost eaten sound
	playGhostEaten(): void {
		if (!this.initialized || this.muted || !this.ghostEatSynth) return
		const now = Tone.now()

		// Quick ascending triumphant burst
		const notes = ['E4', 'G4', 'C5', 'E5']
		notes.forEach((note, i) => {
			this.ghostEatSynth!.triggerAttackRelease(note, '32n', now + i * 0.04)
		})
	}

	// Play death sound
	playDeath(): void {
		if (!this.initialized || this.muted || !this.deathSynth) return

		// Stop eating if active
		this.stopEating()

		const now = Tone.now()

		// Descending chromatic death phrase (slowing down)
		const deathNotes = [
			{ note: 'E5', time: 0, duration: '16n' },
			{ note: 'D5', time: 0.1, duration: '16n' },
			{ note: 'C5', time: 0.2, duration: '16n' },
			{ note: 'B4', time: 0.35, duration: '8n' },
			{ note: 'A4', time: 0.5, duration: '8n' },
			{ note: 'G4', time: 0.7, duration: '8n' },
			{ note: 'F4', time: 0.95, duration: '4n' },
		]

		deathNotes.forEach(({ note, time, duration }) => {
			this.deathSynth!.triggerAttackRelease(note, duration, now + time)
		})
	}

	// Play extra life sound
	playExtraLife(): void {
		if (!this.initialized || this.muted || !this.extraLifeSynth) return
		const now = Tone.now()

		// Triumphant fanfare
		const fanfare = [
			{ notes: ['C4', 'E4'], time: 0 },
			{ notes: ['E4', 'G4'], time: 0.1 },
			{ notes: ['G4', 'C5'], time: 0.2 },
			{ notes: ['C5', 'E5', 'G5'], time: 0.35 },
		]

		fanfare.forEach(({ notes, time }) => {
			this.extraLifeSynth!.triggerAttackRelease(notes, '8n', now + time)
		})
	}

	setMuted(muted: boolean): void {
		this.muted = muted
		if (muted) {
			this.stopEating()
		}
	}

	isMuted(): boolean {
		return this.muted
	}

	dispose(): void {
		if (!this.initialized) return

		this.stopEating()

		this.eatingLoop?.dispose()
		this.eatingSynth?.dispose()
		this.powerSynth?.dispose()
		this.ghostEatSynth?.dispose()
		this.deathSynth?.dispose()
		this.startSynth?.dispose()
		this.extraLifeSynth?.dispose()

		this.eatingLoop = null
		this.eatingSynth = null
		this.powerSynth = null
		this.ghostEatSynth = null
		this.deathSynth = null
		this.startSynth = null
		this.extraLifeSynth = null

		this.initialized = false
	}
}

export const pacmanAudio = new PacmanAudioManager()
