import { useQuery } from 'convex/react';
import { api } from '../../../../convex/_generated/api';
import { Translations } from '../../../../types/i18n';

interface LeaderboardDisplayProps {
  game: string;
  currentPlayerName?: string;
  t: Translations;
}

export function LeaderboardDisplay({ game, currentPlayerName, t }: LeaderboardDisplayProps) {
  const scores = useQuery(api.leaderboard.getTopScores, game ? { game } : 'skip');

  return (
    <div className="leaderboard-container">
      <h3 className="leaderboard-title">{t.games.leaderboard}</h3>
      {scores === undefined ? (
        <p className="leaderboard-loading">...</p>
      ) : scores.length === 0 ? (
        <p className="leaderboard-empty">{t.games.noScoresYet}</p>
      ) : (
        <div className="leaderboard-list">
          {scores.map((entry, i) => {
            const isCurrentPlayer =
              currentPlayerName && entry.playerName === currentPlayerName;
            return (
              <div
                key={entry._id}
                className={`leaderboard-row${isCurrentPlayer ? ' leaderboard-row-highlight' : ''}`}
              >
                <span className="leaderboard-rank">#{i + 1}</span>
                <span className="leaderboard-name">{entry.playerName}</span>
                <span className="leaderboard-score">
                  {entry.score.toLocaleString()}
                </span>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
