import React, { useState, useEffect, useRef, useCallback } from 'react';
import './BrowserWindow.css';
import '../../../styles/themes/index.css';
import { Language } from '../../../types/i18n';
import { getTranslations } from '../../../i18n';
import { BackIcon, ForwardIcon, RefreshIcon, StopIcon, HomeIcon } from '../../icons';
import ThemeDropdown from './ThemeDropdown';
import FavoritesDropdown from './FavoritesDropdown';
import HelpModal from './HelpModal';
import NameChangeModal from './NameChangeModal';

interface BrowserWindowProps {
  currentSection: string;
  children: React.ReactNode;
  onNavigate: (action: string) => void;
  onMinimize?: () => void;
  onOpen?: () => void;
  isMobile?: boolean;
  browserOpen?: boolean;
  browserMinimized?: boolean;
  lang: Language;
  mode: 'night' | 'day' | '';
  setMode: (mode: 'night' | 'day' | '') => void;
  setLang: (lang: Language) => void;
  visitorName: string;
  setName: (name: string) => void;
  onShowWelcome: () => void;
}

const BrowserWindow: React.FC<BrowserWindowProps> = ({
  currentSection,
  children,
  onNavigate,
  onMinimize,
  onOpen,
  isMobile = false,
  browserOpen = true,
  browserMinimized = false,
  lang,
  mode,
  setMode,
  setLang,
  visitorName,
  setName,
  onShowWelcome,
}) => {
  const t = getTranslations(lang);
  const [isMaximized, setIsMaximized] = useState(false);
  const [showBSOD, setShowBSOD] = useState(false);
  const [currentTheme, setCurrentTheme] = useState<string>(() => {
    return localStorage.getItem('browserTheme') || 'notebook';
  });
  const [fileMenuOpen, setFileMenuOpen] = useState(false);
  const [editMenuOpen, setEditMenuOpen] = useState(false);
  const [viewMenuOpen, setViewMenuOpen] = useState(false);
  const [favoritesOpen, setFavoritesOpen] = useState(false);
  const [helpModalOpen, setHelpModalOpen] = useState(false);
  const [statusbarThemeOpen, setStatusbarThemeOpen] = useState(false);
  const [nameModalOpen, setNameModalOpen] = useState(false);
  const browserWindowRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const dragOffsetRef = useRef({ x: 0, y: 0 });
  const fileRef = useRef<HTMLDivElement>(null);
  const editRef = useRef<HTMLDivElement>(null);
  const viewRef = useRef<HTMLDivElement>(null);
  const favoritesRef = useRef<HTMLDivElement>(null);
  const statusbarRef = useRef<HTMLDivElement>(null);

  // Drag handlers — use refs + direct DOM to avoid React re-renders per mousemove.
  const handleDragMove = useCallback((e: MouseEvent) => {
    if (!isDragging.current) return;
    dragOffsetRef.current = {
      x: e.clientX - dragStart.current.x,
      y: e.clientY - dragStart.current.y,
    };
    if (browserWindowRef.current) {
      browserWindowRef.current.style.transform =
        `translate(${dragOffsetRef.current.x}px, ${dragOffsetRef.current.y}px)`;
    }
  }, []);

  const handleDragEnd = useCallback(() => {
    isDragging.current = false;
    document.removeEventListener('mousemove', handleDragMove);
    document.removeEventListener('mouseup', handleDragEnd);
  }, [handleDragMove]);

  const handleDragStart = useCallback((e: React.MouseEvent) => {
    if (isMobile || isMaximized) return;
    if ((e.target as HTMLElement).closest('.browser-titlebar-controls')) return;
    isDragging.current = true;
    dragStart.current = {
      x: e.clientX - dragOffsetRef.current.x,
      y: e.clientY - dragOffsetRef.current.y,
    };
    document.addEventListener('mousemove', handleDragMove);
    document.addEventListener('mouseup', handleDragEnd);
  }, [isMobile, isMaximized, handleDragMove, handleDragEnd]);

  // Cleanup drag listeners on unmount
  useEffect(() => {
    return () => {
      document.removeEventListener('mousemove', handleDragMove);
      document.removeEventListener('mouseup', handleDragEnd);
    };
  }, [handleDragMove, handleDragEnd]);

  // Close dropdowns when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (fileRef.current && !fileRef.current.contains(event.target as Node)) {
        setFileMenuOpen(false);
      }
      if (editRef.current && !editRef.current.contains(event.target as Node)) {
        setEditMenuOpen(false);
      }
      if (viewRef.current && !viewRef.current.contains(event.target as Node)) {
        setViewMenuOpen(false);
      }
      if (favoritesRef.current && !favoritesRef.current.contains(event.target as Node)) {
        setFavoritesOpen(false);
      }
      if (statusbarRef.current && !statusbarRef.current.contains(event.target as Node)) {
        setStatusbarThemeOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Sync isMaximized with browserOpen on mobile
  useEffect(() => {
    if (isMobile && browserOpen) {
      setIsMaximized(true);
    }
  }, [isMobile, browserOpen]);

  const setTheme = useCallback((theme: string, source: 'menubar' | 'statusbar') => {
    setCurrentTheme(theme);
    localStorage.setItem('browserTheme', theme);
    if (source === 'menubar') {
      setViewMenuOpen(false);
    } else {
      setStatusbarThemeOpen(false);
    }
  }, []);

  const toggleStatusbarTheme = useCallback(() => {
    setStatusbarThemeOpen(prev => !prev);
  }, []);

  const handleMenubarThemeSelect = useCallback((theme: string) => setTheme(theme, 'menubar'), [setTheme]);
  const handleStatusbarThemeSelect = useCallback((theme: string) => setTheme(theme, 'statusbar'), [setTheme]);

  const handleSelectLang = useCallback((newLang: Language) => {
    setLang(newLang);
    setEditMenuOpen(false);
  }, [setLang]);

  const handleSelectMode = useCallback((newMode: 'night' | 'day') => {
    setMode(newMode);
    setEditMenuOpen(false);
  }, [setMode]);

  const handleStatusbarLangToggle = useCallback(() => {
    setLang(lang === 'en' ? 'es' : 'en');
  }, [lang, setLang]);

  const handleStatusbarModeToggle = useCallback(() => {
    setMode(mode === 'night' ? 'day' : 'night');
  }, [mode, setMode]);

  const handleChangeName = useCallback(() => {
    setFileMenuOpen(false);
    setNameModalOpen(true);
  }, []);

  const handleSaveName = useCallback((newName: string) => {
    setName(newName);
    document.cookie = `name=${newName}`;
  }, [setName]);

  const THEME_ORDER = ['classic', 'vaporwave', 'terminal', 'notebook'];

  useEffect(() => {
    const handleKeyboard = (e: KeyboardEvent) => {
      const tag = (e.target as HTMLElement).tagName;
      if (tag === 'INPUT' || tag === 'TEXTAREA' || (e.target as HTMLElement).isContentEditable) return;

      switch (e.key.toLowerCase()) {
        case 't': {
          const idx = THEME_ORDER.indexOf(currentTheme);
          const next = THEME_ORDER[(idx + 1) % THEME_ORDER.length];
          setCurrentTheme(next);
          localStorage.setItem('browserTheme', next);
          break;
        }
        case 'l':
          setLang(lang === 'en' ? 'es' : 'en');
          break;
        case 'm':
          setMode(mode === 'night' ? 'day' : 'night');
          break;
        case 'q':
          onShowWelcome();
          break;
        case 'p': {
          const radio = document.querySelector('#player-controls') as HTMLElement | null;
          if (radio) radio.click();
          break;
        }
        case 'n':
          setNameModalOpen(true);
          break;
        case 'h':
          setHelpModalOpen(prev => !prev);
          break;
      }
    };
    document.addEventListener('keydown', handleKeyboard);
    return () => document.removeEventListener('keydown', handleKeyboard);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentTheme, lang, mode, setLang, setMode, onShowWelcome]);

  const handleShowWelcome = useCallback(() => {
    setFileMenuOpen(false);
    onShowWelcome();
  }, [onShowWelcome]);

  const getSectionUrl = (section: string): string => {
    const urls: { [key: string]: string } = {
      '': 'http://maw.dev/index.html',
      'goTo-about': 'http://maw.dev/about-me.htm',
      'goTo-work': 'http://maw.dev/work/tech-stack.html',
      'goTo-portfolio': 'http://maw.dev/portfolio/gallery.cgi',
      'goTo-contact': 'http://maw.dev/contact/guestbook.php',
    };
    return urls[section] || 'http://maw.dev/';
  };

  const getSectionTitle = (section: string): string => {
    const titles: { [key: string]: string } = {
      '': t.browser.titles.home,
      'goTo-about': t.browser.titles.about,
      'goTo-work': t.browser.titles.work,
      'goTo-portfolio': t.browser.titles.portfolio,
      'goTo-contact': t.browser.titles.contact,
      'goTo-games': t.browser.titles.games,
    };
    return titles[section] || t.browser.titles.home;
  };

  const handleBack = () => {
    onNavigate('');
  };

  const handleHome = () => {
    onNavigate('');
  };

  // Handle click on browser when mobile and hidden - opens it
  const handleBrowserClick = () => {
    if (isMobile && !browserOpen) {
      onOpen?.();
      setIsMaximized(true);
    }
  };

  return (
    <div
      ref={browserWindowRef}
      className={`browser-window ${isMaximized ? 'maximized' : ''} ${browserMinimized ? 'minimized' : ''} ${isDragging.current ? 'dragging' : ''}`}
      onClick={handleBrowserClick}
    >
      {/* Title Bar */}
      <div
        className="browser-titlebar"
        onMouseDown={handleDragStart}
        onDoubleClick={() => {
          if (!isMobile) {
            setIsMaximized(!isMaximized);
            dragOffsetRef.current = { x: 0, y: 0 };
            if (browserWindowRef.current) browserWindowRef.current.style.transform = '';
          }
        }}
      >
        <div className="browser-titlebar-text">
          <span className="browser-icon">🌐</span>
          {getSectionTitle(currentSection)}
        </div>
        <div className="browser-titlebar-controls">
          <button
            className="titlebar-button minimize"
            aria-label="Minimize"
            onClick={(e) => {
              e.stopPropagation();
              if (isMobile) {
                // Mobile: only works when maximized, returns to hidden state
                if (isMaximized) {
                  setIsMaximized(false);
                  onMinimize?.();
                }
              } else {
                // Desktop: hide browser completely
                onMinimize?.();
              }
            }}
          >
            _
          </button>
          <button
            className="titlebar-button maximize"
            aria-label="Maximize"
            onClick={(e) => {
              e.stopPropagation();
              if (isMobile) {
                // Mobile when maximized: do nothing
                if (isMaximized) return;
                // Mobile when hidden: maximize
                setIsMaximized(true);
                onOpen?.();
              } else {
                // Desktop: toggle maximize
                setIsMaximized(!isMaximized);
                dragOffsetRef.current = { x: 0, y: 0 };
                if (browserWindowRef.current) browserWindowRef.current.style.transform = '';
              }
            }}
          >
            □
          </button>
          <button
            className="titlebar-button close"
            aria-label="Close"
            onClick={(e) => {
              e.stopPropagation();
              if (isMobile && !isMaximized) {
                // Mobile hidden state: do nothing
                return;
              }
              // Desktop or mobile maximized: trigger BSOD
              setShowBSOD(true);
            }}
          >
            ×
          </button>
        </div>
      </div>

      {/* Menu Bar */}
      <div className="browser-menubar">
        <div className="menu-item-wrapper" ref={fileRef}>
          <span className="menu-item" onClick={() => setFileMenuOpen(prev => !prev)}>
            {t.browser.menus.file}
          </span>
          {fileMenuOpen && (
            <div className="settings-dropdown">
              <button onClick={handleChangeName}>{t.browser.settings.changeName}</button>
              <div className="settings-separator" />
              <button onClick={handleShowWelcome}>{t.browser.settings.showWelcome}</button>
            </div>
          )}
        </div>
        <div className="menu-item-wrapper" ref={editRef}>
          <span className="menu-item" onClick={() => setEditMenuOpen(prev => !prev)}>
            {t.browser.menus.edit}
          </span>
          {editMenuOpen && (
            <div className="settings-dropdown">
              <div className="settings-section">
                <div className="settings-section-header">{t.browser.settings.language}</div>
                <button
                  className={lang === 'en' ? 'active' : ''}
                  onClick={() => handleSelectLang('en')}
                >
                  English
                </button>
                <button
                  className={lang === 'es' ? 'active' : ''}
                  onClick={() => handleSelectLang('es')}
                >
                  Español
                </button>
              </div>
              <div className="settings-separator" />
              <div className="settings-section">
                <div className="settings-section-header">{t.browser.settings.mode}</div>
                <button
                  className={mode === 'day' ? 'active' : ''}
                  onClick={() => handleSelectMode('day')}
                >
                  {t.browser.settings.dayMode}
                </button>
                <button
                  className={mode === 'night' ? 'active' : ''}
                  onClick={() => handleSelectMode('night')}
                >
                  {t.browser.settings.nightMode}
                </button>
              </div>
            </div>
          )}
        </div>
        <div className="menu-item-wrapper" ref={viewRef}>
          <span className="menu-item" onClick={() => setViewMenuOpen(prev => !prev)}>
            {t.browser.menus.view}
          </span>
          {viewMenuOpen && (
            <ThemeDropdown
              currentTheme={currentTheme}
              onSelectTheme={handleMenubarThemeSelect}
              themes={t.browser.themes}
              variant="menubar"
              header={t.browser.settings.theme}
            />
          )}
        </div>
        <div className="menu-item-wrapper" ref={favoritesRef}>
          <span className="menu-item" onClick={() => setFavoritesOpen(prev => !prev)}>
            {t.browser.menus.favorites}
          </span>
          {favoritesOpen && (
            <FavoritesDropdown translations={t.browser.favorites} />
          )}
        </div>
        <span className="menu-item" onClick={() => setHelpModalOpen(true)}>
          {t.browser.menus.help}
        </span>
      </div>

      {/* Navigation Bar */}
      <div className="browser-navbar">
        <div className="nav-buttons">
          <button
            className="nav-button back"
            onClick={handleBack}
            disabled={currentSection === ''}
            aria-label="Back"
          >
            <BackIcon />
          </button>
          <button className="nav-button forward" disabled aria-label="Forward">
            <ForwardIcon />
          </button>
          <button className="nav-button refresh" aria-label="Refresh">
            <RefreshIcon />
          </button>
          <button className="nav-button stop" aria-label="Stop">
            <StopIcon />
          </button>
          <button className="nav-button home" onClick={handleHome} aria-label="Home">
            <HomeIcon />
          </button>
        </div>
        <div className="nav-addressbar">
          <input
            type="text"
            value={getSectionUrl(currentSection)}
            readOnly
            className="addressbar-input"
          />
        </div>
      </div>

      {/* Content Area */}
      <div className="browser-content">
        <div className={`browser-viewport theme-${currentTheme}`}>{children}</div>
      </div>

      {/* BSOD Easter Egg */}
      {showBSOD && (
        <div className="bsod-overlay" onClick={() => setShowBSOD(false)}>
          <div className="bsod-content">
            <h1>{t.browser.bsod.title}</h1>
            <p className="bsod-main-text">{t.browser.bsod.mainText}</p>
            <p>{t.browser.bsod.collectingError}</p>
            <p className="bsod-error">{t.browser.bsod.errorCode}</p>
            <p className="bsod-code">{t.browser.bsod.stopCode}</p>
            <p className="bsod-hint">{t.browser.bsod.clickToRestart}</p>
          </div>
        </div>
      )}

      {/* Status Bar */}
      <div className="browser-statusbar">
        <div className="status-text">{t.browser.statusDone}</div>
        <div className="status-icons">
          <button className="status-lang-button" onClick={handleStatusbarLangToggle}>
            🌐 {lang.toUpperCase()}
          </button>
          <button className="status-mode-button" onClick={handleStatusbarModeToggle}>
            {mode === 'night' ? '🌙' : '☀️'}
          </button>
          <div className="status-theme-selector" ref={statusbarRef}>
            <button
              className="status-theme-button"
              onClick={toggleStatusbarTheme}
              aria-label={t.browser.menus.themes}
            >
              🎨 {t.browser.themes[currentTheme as keyof typeof t.browser.themes] || currentTheme}
            </button>
            {statusbarThemeOpen && (
              <ThemeDropdown
                currentTheme={currentTheme}
                onSelectTheme={handleStatusbarThemeSelect}
                themes={t.browser.themes}
                variant="statusbar"
              />
            )}
          </div>
          <span className="status-icon">🔒</span>
          <span className="status-zone">{t.browser.statusZone}</span>
        </div>
      </div>

      {/* Name Change Modal */}
      <NameChangeModal
        isOpen={nameModalOpen}
        currentName={visitorName}
        onSave={handleSaveName}
        onClose={() => setNameModalOpen(false)}
        lang={lang}
      />

      {/* Help Modal */}
      <HelpModal
        isOpen={helpModalOpen}
        onClose={() => setHelpModalOpen(false)}
        translations={t.browser.help}
      />
    </div>
  );
};

export default BrowserWindow;
