import React, { useEffect } from 'react';
import { Translations } from '../../../types/i18n';

import './PauseOverlay.css';

interface PauseOverlayProps {
  onResume: () => void;
  translations: Translations;
}

const PauseOverlay: React.FC<PauseOverlayProps> = ({ onResume, translations }) => {
  useEffect(() => {
    const handleKeyPress = () => onResume();
    document.addEventListener('keydown', handleKeyPress);
    return () => document.removeEventListener('keydown', handleKeyPress);
  }, [onResume]);

  return (
    <div className="pause-overlay" onClick={onResume}>
      <div className="pause-content pixel-border">
        <h1>{translations.browser.pause.title}</h1>
        <p className="pause-hint">{translations.browser.pause.hint}</p>
      </div>
    </div>
  );
};

export default PauseOverlay;
